#include <bits/stdc++.h>
using namespace std;
int n,m,t[10004],x[10004],y[10004],dp[10004],ans=0;
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++)
		scanf("%d%d%d",&t[i],&x[i],&y[i]);
	for(int i=1;i<=m;i++){
		dp[i]=1;
		for(int j=1;j<i;j++)
			if(abs(x[i]-x[j])+abs(y[i]-y[j])<=t[i]-t[j])
				dp[i]=max(dp[i],dp[j]+1);
		ans=max(ans,dp[i]);
	}
	printf("%d",ans);
	return 0;
}
